<script setup lang="ts">
import { computed, nextTick, onMounted, ref, watch } from 'vue'
import { useRoute } from 'vue-router'
import { ElMessage, ElMessageBox } from 'element-plus'
import AsyncState from '@/components/AsyncState.vue';import PracticeWorksheet, { type WorksheetMode } from '@/components/PracticeWorksheet.vue';import ResultSelector from '@/components/ResultSelector.vue'
import { listAllRoundReviews } from '@/api/reviews'
import { createRound, downloadRecitation, getSession, markSessionPrinted, putBatchRoundResults } from '@/api/practiceSessions'
import { newEventId, normalizeApiError } from '@/api/client';import { useAsyncState } from '@/composables/useAsyncState'
import type { PracticeItem, PracticeRound, PracticeSession, ReviewLog, ReviewStatus } from '@/types/domain'

interface SessionBundle { session: PracticeSession; round: PracticeRound | null; reviews: ReviewLog[] }
type SessionTab = 'worksheet' | 'answer' | 'record'
const route=useRoute();const id=Number(route.params.id);const state=useAsyncState<SessionBundle>();const activeTab=ref<SessionTab>('worksheet');const worksheetMode=ref<WorksheetMode>('cn-to-en');const includeAnswer=ref(true);const round=ref<PracticeRound|null>(null);const results=ref(new Map<number,ReviewLog>());const selections=ref(new Map<number,ReviewStatus>());const eventIds=new Map<number,string>();const error=ref('');const starting=ref(false);const saving=ref(false);const markingPrinted=ref(false);const onlyUnrecorded=ref(false);const mobileIndex=ref(0);const roundKey=ref<string|null>(null);const batchKey=ref<string|null>(null);const printKey=ref<string|null>(null);const exporting=ref(false)
const session=computed(()=>state.data.value?.session);const items=computed(()=>session.value?.items||[]);const answered=computed(()=>results.value.size);const pendingItems=computed(()=>items.value.filter(item=>{const selected=selections.value.get(item.item_id);return selected!==undefined&&selected!==results.value.get(item.item_id)?.status}));const visibleItems=computed(()=>onlyUnrecorded.value?items.value.filter(item=>!results.value.has(item.item_id)):items.value);const mobileItem=computed(()=>visibleItems.value[Math.min(mobileIndex.value,Math.max(visibleItems.value.length-1,0))]);const lastModified=computed(()=>[...results.value.values()].sort((a,b)=>b.updated_at.localeCompare(a.updated_at))[0]?.updated_at||null)
const countLabels:Record<string,string>={new:'新词',error:'错词',due:'到期',custom:'自定义',new_words:'新词',error_words:'错词',due_words:'到期',custom_words:'自定义'}
const sourceLabel=(source:string)=>countLabels[source]||source
function installReviews(reviews:ReviewLog[]){const saved=new Map<number,ReviewLog>();const selected=new Map<number,ReviewStatus>();eventIds.clear();for(const review of reviews){if(review.session_item_id!==null){saved.set(review.session_item_id,review);selected.set(review.session_item_id,review.status);eventIds.set(review.session_item_id,review.client_event_id)}}results.value=saved;selections.value=selected}
async function load(){const bundle=await state.run(async signal=>{const loaded=await getSession(id,signal);const restored=(loaded.rounds||[]).filter(item=>item.mode==='offline').sort((a,b)=>b.started_at.localeCompare(a.started_at)||b.round_id-a.round_id)[0]||null;const reviews=restored?await listAllRoundReviews(restored.round_id,signal):[];return{session:loaded,round:restored,reviews}}).catch(()=>undefined);if(bundle){round.value=bundle.round;installReviews(bundle.reviews);mobileIndex.value=0}}
async function startRound(){if(!session.value)return;starting.value=true;error.value='';roundKey.value ||= newEventId();try{round.value=await createRound(id,'offline',roundKey.value);roundKey.value=null;installReviews([]);mobileIndex.value=0;activeTab.value='record';ElMessage.success('已开始一轮新的线下结果回录')}catch(e){error.value=normalizeApiError(e).message}finally{starting.value=false}}
function select(itemId:number,status:ReviewStatus){if(!round.value)return;const next=new Map(selections.value);next.set(itemId,status);selections.value=next;if(!eventIds.has(itemId))eventIds.set(itemId,newEventId());batchKey.value=null}
async function recoverConflict(desired:Map<number,ReviewStatus>){if(!round.value)return;const latest=await listAllRoundReviews(round.value.round_id);installReviews(latest);try{await ElMessageBox.confirm('服务器中的结果已经更新。要保留您刚才的选择并基于最新版本再次保存吗？','发现并发修改',{confirmButtonText:'保留我的选择',cancelButtonText:'采用服务器最新值',distinguishCancelAndClose:true,type:'warning'});const next=new Map(selections.value);for(const [itemId,status] of desired)next.set(itemId,status);selections.value=next;batchKey.value=null;error.value='已加载服务器最新版本，请再次点击保存以覆盖。'}catch{error.value='已采用服务器中的最新结果。'}}
async function saveBatch(){if(!round.value||pendingItems.value.length===0)return;saving.value=true;error.value='';const desired=new Map(pendingItems.value.map(item=>[item.item_id,selections.value.get(item.item_id)!]));batchKey.value ||= newEventId();try{const response=await putBatchRoundResults(round.value.round_id,pendingItems.value.map(item=>{const existing=results.value.get(item.item_id);return{item_id:item.item_id,status:selections.value.get(item.item_id)!,client_event_id:existing?.client_event_id||eventIds.get(item.item_id)!,...(existing?{expected_version:existing.version}:{})}}),batchKey.value);round.value=response.round;const saved=new Map(results.value);for(const review of response.items){if(review.session_item_id!==null){saved.set(review.session_item_id,review);eventIds.set(review.session_item_id,review.client_event_id)}}results.value=saved;batchKey.value=null;const fresh=await getSession(id);if(state.data.value)state.data.value={...state.data.value,session:fresh};ElMessage.success(`已原子保存 ${response.items.length} 项结果`)}catch(e){const normalized=normalizeApiError(e);if(normalized.isConflict)await recoverConflict(desired);else error.value=`保存失败，您的选择仍保留：${normalized.message}`;}finally{saving.value=false}}
async function printSheet(){window.print();try{await ElMessageBox.confirm('打印窗口已打开。系统无法自动判断纸张是否真正输出；请在确认已打印或保存 PDF 后继续。','确认打印完成',{confirmButtonText:'确认已完成打印',cancelButtonText:'暂不确认',type:'info'});markingPrinted.value=true;printKey.value ||= newEventId();const updated=await markSessionPrinted(id,printKey.value);printKey.value=null;if(state.data.value)state.data.value={...state.data.value,session:{...state.data.value.session,printed_at:updated.printed_at,version:updated.version}};ElMessage.success('已记录打印完成时间')}catch(e){if(e==='cancel'||e==='close')return;error.value=normalizeApiError(e).message}finally{markingPrinted.value=false}}
async function exportRecitation(format:'pdf'|'md'){exporting.value=true;try{await downloadRecitation(id,format);ElMessage.success(format==='pdf'?'已导出 PDF 背诵表':'已导出 Markdown 背诵表')}catch(e){error.value=normalizeApiError(e).message}finally{exporting.value=false}}
function previous(){if(mobileIndex.value>0)mobileIndex.value--}function next(){if(mobileIndex.value<visibleItems.value.length-1)mobileIndex.value++}
watch(visibleItems,()=>{mobileIndex.value=Math.min(mobileIndex.value,Math.max(visibleItems.value.length-1,0))});watch(activeTab,async()=>{await nextTick();document.querySelector<HTMLElement>('.session-view-panel')?.focus({preventScroll:true})});onMounted(()=>{if(route.query.view==='print')activeTab.value='worksheet';load()})
</script>
<template><section class="page session-page"><AsyncState :phase="state.phase.value" :error="state.error.value" @retry="load"><template v-if="session"><div class="page-heading no-print"><div><p class="eyebrow">SESSION #{{ session.session_id }}</p><p>{{ new Date(session.generated_at).toLocaleString('zh-CN') }} · 种子 {{ session.seed }}<span v-if="session.printed_at"> · 已打印 {{ new Date(session.printed_at).toLocaleString('zh-CN') }}</span></p></div><div class="button-row"><span v-if="session.created_by_actor_type==='api_client'" class="source-pill">外部 Skill · {{ session.skill_name||'未命名客户端' }}</span><el-button :loading="markingPrinted" @click="printSheet">打印 / 保存 PDF</el-button><el-dropdown trigger="click" :loading="exporting" @command="(c:string)=>exportRecitation(c as 'pdf'|'md')"><el-button :loading="exporting">导出背诵表 ▾</el-button><template #dropdown><el-dropdown-menu><el-dropdown-item command="pdf">PDF 背诵表</el-dropdown-item><el-dropdown-item command="md">Markdown 背诵表</el-dropdown-item></el-dropdown-menu></template></el-dropdown><el-button :loading="starting" type="primary" @click="startRound">{{ round?'开始新一轮':'开始结果回录' }}</el-button></div></div>
  <div class="session-summary no-print"><article><small>题目数量</small><strong>{{ items.length }}</strong></article><article><small>已回录</small><strong>{{ answered }} / {{ items.length }}</strong></article><article><small>策略版本</small><strong>{{ session.strategy_version }}</strong></article><article><small>会话状态</small><strong>{{ session.status==='active'?'进行中':'已归档' }}</strong></article></div>
  <div class="panel strategy-summary no-print"><div><strong>请求数量</strong><span v-for="(value,key) in session.requested_counts" :key="key">{{ sourceLabel(String(key)) }} {{ value }}</span></div><div><strong>实际入选</strong><span v-for="(value,key) in session.actual_counts" :key="key">{{ sourceLabel(String(key)) }} {{ value }}</span></div></div>
  <div class="view-toolbar no-print"><div class="view-tabs" role="tablist" aria-label="复习表视图"><button type="button" :class="{active:activeTab==='worksheet'}" role="tab" :aria-selected="activeTab==='worksheet'" @click="activeTab='worksheet'">复习表</button><button type="button" :class="{active:activeTab==='answer'}" role="tab" :aria-selected="activeTab==='answer'" @click="activeTab='answer'">答案</button><button type="button" :class="{active:activeTab==='record'}" role="tab" :aria-selected="activeTab==='record'" @click="activeTab='record'">结果回录</button></div><div v-if="activeTab!=='record'" class="print-options"><el-radio-group v-model="worksheetMode" size="small"><el-radio-button value="cn-to-en">看中文写英文</el-radio-button><el-radio-button value="en-to-cn">看英文写中文</el-radio-button><el-radio-button value="cloze">例句填空</el-radio-button></el-radio-group><el-checkbox v-model="includeAnswer">打印时附答案页</el-checkbox></div></div>
  <div v-if="error" class="error-box no-print" role="alert">{{ error }}</div>
  <div class="print-container session-view-panel" tabindex="-1"><div class="print-section print-question" :class="{'screen-active':activeTab==='worksheet'}"><PracticeWorksheet :session="session" :mode="worksheetMode"/></div><div class="print-section print-answer" :class="{'screen-active':activeTab==='answer','include-answer':includeAnswer}"><PracticeWorksheet :session="session" :mode="worksheetMode" answer/></div></div>
  <section v-show="activeTab==='record'" class="record-view session-view-panel no-print" tabindex="-1"><div v-if="round" class="round-banner" aria-live="polite"><div><strong>线下回录轮次 #{{ round.round_id }}</strong><span>已保存 {{ answered }} / {{ items.length }}<template v-if="lastModified"> · 最后修改 {{ new Date(lastModified).toLocaleString('zh-CN') }}</template></span></div><el-progress :percentage="Math.round(answered/(items.length||1)*100)"/></div><div v-else class="panel intro-banner"><strong>完成纸面复习后，开始一次新的结果回录。</strong><p>每次实际复习都创建新轮次；同一轮中的改选只会纠正本次流水。</p><el-button type="primary" :loading="starting" @click="startRound">开始结果回录</el-button></div>
    <div v-if="round" class="record-actions"><el-checkbox v-model="onlyUnrecorded">只看未录入</el-checkbox><span>待保存 {{ pendingItems.length }} 项</span><el-button type="primary" :loading="saving" :disabled="pendingItems.length===0" @click="saveBatch">批量保存本轮结果</el-button></div>
    <div v-if="round&&visibleItems.length===0" class="panel empty-record">所有题目都已录入。仍可关闭“只看未录入”后直接修改。</div>
    <div v-if="round" class="desktop-recorder local-scroll"><el-table :data="visibleItems" row-key="item_id" style="min-width:850px"><el-table-column prop="position" label="序号" width="70"/><el-table-column label="单词" min-width="190"><template #default="{row}"><strong class="record-en">{{ row.word.en_word }}</strong><small>{{ row.word.phonetic }}</small></template></el-table-column><el-table-column label="释义 / 入选原因" min-width="250"><template #default="{row}"><strong>{{ row.word.cn_meaning }}</strong><p class="reason">{{ row.reason }}</p></template></el-table-column><el-table-column label="本轮结果" min-width="330"><template #default="{row}"><ResultSelector compact :model-value="selections.get(row.item_id)||null" :disabled="saving" @select="status=>select(row.item_id,status)"/><small class="save-state">{{ pendingItems.some(item=>item.item_id===row.item_id)?'待保存':results.has(row.item_id)?'已保存，可改选':'尚未选择' }}</small></template></el-table-column></el-table></div>
    <div v-if="round&&mobileItem" class="mobile-recorder"><article class="record-card panel"><div class="record-position">{{ mobileItem.position }}</div><div class="tag-list"><span v-for="source in mobileItem.source_categories" :key="source" class="source-pill">{{ sourceLabel(source) }}</span></div><h2>{{ mobileItem.word.en_word }}</h2><p class="phonetic">{{ mobileItem.word.phonetic }}</p><strong>{{ mobileItem.word.cn_meaning }}</strong><p class="reason">{{ mobileItem.reason }}</p><p v-if="mobileItem.word.example_sentence" class="example">{{ mobileItem.word.example_sentence }}</p><ResultSelector :model-value="selections.get(mobileItem.item_id)||null" :disabled="saving" @select="status=>select(mobileItem!.item_id,status)"/><small class="save-state">{{ pendingItems.some(item=>item.item_id===mobileItem?.item_id)?'待保存':results.has(mobileItem.item_id)?'已保存，可改选':'尚未选择' }}</small></article><nav class="mobile-record-nav" aria-label="回录题目导航"><button type="button" :disabled="mobileIndex===0" @click="previous">← 上一题</button><span>{{ mobileIndex+1 }} / {{ visibleItems.length }}</span><button type="button" :disabled="mobileIndex>=visibleItems.length-1" @click="next">下一题 →</button></nav></div>
  </section></template></AsyncState></section></template>
<style scoped>.session-summary{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.session-summary article{display:grid;padding:14px 16px;border:1px solid var(--line);border-radius:13px;background:var(--paper)}.session-summary small{color:var(--muted)}.session-summary strong{margin-top:4px;font:700 1.25rem Georgia,serif}.strategy-summary{display:flex;gap:28px}.strategy-summary>div{display:flex;gap:12px;flex-wrap:wrap}.strategy-summary strong{color:var(--green-800)}.strategy-summary span{color:var(--muted)}.view-toolbar{display:flex;justify-content:space-between;align-items:center;gap:16px;padding:8px;border:1px solid var(--line);border-radius:14px;background:var(--paper)}.view-tabs{display:flex;gap:5px}.view-tabs button{min-height:44px;padding:8px 16px;border:0;border-radius:10px;background:transparent;color:var(--muted);font-weight:700}.view-tabs button.active{background:var(--green-950);color:#fff}.print-options{display:flex;align-items:center;gap:14px}.print-container{outline:none}.print-section{display:none;border:1px solid var(--line);box-shadow:var(--shadow)}.print-section.screen-active{display:block}.round-banner{position:sticky;top:10px;z-index:8;display:grid;grid-template-columns:1fr minmax(180px,340px);align-items:center;gap:20px;padding:14px 18px;background:var(--green-950);color:#fff;border-radius:14px;box-shadow:var(--shadow)}.round-banner>div{display:grid;gap:3px}.round-banner span{color:#bfd1c8;font-size:.82rem}.intro-banner p{color:var(--muted)}.record-view{display:grid;gap:12px;outline:none}.record-actions{display:flex;justify-content:flex-end;align-items:center;gap:14px;padding:10px 0}.record-actions span{color:var(--muted)}.record-en{display:block;font:700 1.15rem Georgia,serif}.record-en+small{display:block;color:var(--green-800)}.reason{margin:5px 0;color:var(--muted);font-size:.82rem}.save-state{display:block;text-align:center;margin-top:5px;color:var(--muted)}.mobile-recorder{display:none}.record-card{position:relative}.record-position{position:absolute;right:16px;top:16px;width:34px;height:34px;display:grid;place-items:center;border-radius:50%;background:var(--green-100);font-weight:800}.record-card h2{font:700 1.8rem Georgia,serif;margin:12px 0 2px}.record-card .phonetic{color:var(--green-800)}.record-card .example{color:var(--muted);font-style:italic}.mobile-record-nav{display:grid;grid-template-columns:1fr auto 1fr;align-items:center;gap:8px}.mobile-record-nav button{min-height:44px;border:1px solid var(--line);border-radius:10px;background:#fff;color:var(--green-800)}.mobile-record-nav button:last-child{justify-self:stretch}.mobile-record-nav span{text-align:center}.empty-record{text-align:center;color:var(--muted)}@media(max-width:1023px){.view-toolbar{align-items:flex-start;flex-direction:column}.print-options{width:100%;justify-content:space-between}.session-summary{grid-template-columns:repeat(2,1fr)}}@media(max-width:639px){.strategy-summary{display:grid;gap:10px}.view-toolbar{padding:6px}.view-tabs{width:100%;display:grid;grid-template-columns:repeat(3,1fr)}.view-tabs button{padding:6px}.print-options{display:grid;gap:8px;overflow-x:auto}.print-options :deep(.el-radio-group){display:flex;flex-wrap:nowrap}.record-actions{position:sticky;top:0;z-index:7;display:grid;grid-template-columns:1fr auto;padding:10px;background:var(--paper);border:1px solid var(--line);border-radius:10px}.record-actions .el-button{grid-column:1/-1;min-height:44px}.desktop-recorder{display:none}.mobile-recorder{display:grid;gap:10px}.session-summary{grid-template-columns:1fr 1fr}.session-summary article{padding:11px}.round-banner{position:relative;top:auto;grid-template-columns:1fr}.print-section{box-shadow:none}}
</style>
